mutable montyN = 100

montySimData = {
  const n = montyN;
  let stayWins = 0, switchWins = 0;
  const stayData = [];
  const switchData = [];

  for (let i = 1; i &lt;= n; i++) {
    const car = Math.floor(Math.random() * 3);
    const pick = Math.floor(Math.random() * 3);
    if (pick === car) stayWins++;
    else switchWins++;
    stayData.push({game: i, rate: stayWins / i, strategy: "Stay"});
    switchData.push({game: i, rate: switchWins / i, strategy: "Switch"});
  }

  return {stayData, switchData, stayRate: stayWins / n, switchRate: switchWins / n, n};
}
















