    const corners = isT
      ? [[0,0], transform(v1[0],v1[1],m),
         transform(v1[0]+v2[0],v1[1]+v2[1],m), transform(v2[0],v2[1],m)]
      : [[0,0], v1, [v1[0]+v2[0],v1[1]+v2[1]], v2];

    const fc = isT ? "#FFB347" : "#87CEEB";
    const ec = isT ? "#CC7000" : "#4682B4";
    svg.append("polygon")
      .attr("points", corners.map(([x,y]) =&gt; `${sx(x)},${sy(y)}`).join(" "))
      .attr("fill",fc).attr("fill-opacity",0.3).attr("stroke",ec).attr("stroke-width",2);
    for (const [x,y] of corners)
      svg.append("circle").attr("cx",sx(x)).attr("cy",sy(y)).attr("r",4).attr("fill",ec);

    // Arrows
    for (const [color, id] of [["#4682B4","b1"],["#CC7000","o1"],["#2E8B57","g1"],["#C71585","p1"]]) {
      svg.append("defs").append("marker").attr("id",`ar-${id}`)
        .attr("viewBox","0 0 10 10").attr("refX",9).attr("refY",5)
        .attr("markerWidth",8).attr("markerHeight",8).attr("orient","auto-start-reverse")
        .append("path").attr("d","M 0 0 L 10 5 L 0 10 z").attr("fill",color);
    }

    function arrow(tx, ty, color, markerId, label) {
      const [px,py] = isT ? transform(tx,ty,m) : [tx,ty];
      svg.append("line").attr("x1",sx(0)).attr("y1",sy(0))
        .attr("x2",sx(px)).attr("y2",sy(py))
        .attr("stroke",color).attr("stroke-width",2.5)
        .attr("marker-end",`url(#ar-${markerId})`);
      svg.append("text").attr("x",sx(px)+8).attr("y",sy(py)-8)
        .attr("font-size",12).attr("fill",color).attr("font-weight","bold").text(label);
    }
    arrow(v1[0],v1[1], isT?"#CC7000":"#4682B4", isT?"o1":"b1", isT?"v₁'":"v₁");
    arrow(v2[0],v2[1], isT?"#C71585":"#2E8B57", isT?"p1":"g1", isT?"v₂'":"v₂");

    // Face
    if (showImageToggle) {
      const tp = (x,y) =&gt; isT ? transform(x,y,m) : [x,y];
      const headPath = faceHead.map(([x,y],i) =&gt; {
        const [px,py] = tp(x,y);
        return `${i===0?'M':'L'} ${sx(px)} ${sy(py)}`;
      }).join(" ") + " Z";
      svg.append("path").attr("d",headPath)
        .attr("fill","none").attr("stroke","#555").attr("stroke-width",2);
      for (const eyePts of faceEyes) {
        const eyePath = eyePts.map(([x,y],i) =&gt; {
          const [px,py] = tp(x,y);
          return `${i===0?'M':'L'} ${sx(px)} ${sy(py)}`;
        }).join(" ") + " Z";
        svg.append("path").attr("d",eyePath).attr("fill","#555").attr("stroke","none");
      }
      const mouthPath = faceMouth.map(([x,y],i) =&gt; {
        const [px,py] = tp(x,y);
        return `${i===0?'M':'L'} ${sx(px)} ${sy(py)}`;
      }).join(" ");
      svg.append("path").attr("d",mouthPath)
        .attr("fill","none").attr("stroke","#555").attr("stroke-width",2);
    }

    svg.append("text").attr("x",W/2).attr("y",20)
      .attr("text-anchor","middle").attr("font-size",14).attr("fill","gray").text(title);
  }

  drawPlot(container, "Original", {a:1,b:0,c:0,d:1}, false);
  drawPlot(container, "Transformed", currentMat, true);

  return container.node();
}






